/* ELEV_FR — grille d'élévation France métropole + Corse, générée depuis le DEM AWS terrarium z9 (~300 m/px).
   Valeur = altitude MAX du terrain dans la maille (0,025° ≈ 2 km), en pieds AMSL, mer = 0. Usage : ELEV_FR_get(lat,lon) → ft. */
window.ELEV_FR={lat0:41.0,lon0:-5.5,dlat:0.025,dlon:0.025,rows:420,cols:620,unit:'ft',b64:""};
window.ELEV_FR_get=function(lat,lon){var E=window.ELEV_FR;if(!E)return null;if(!E._u16){try{var b=atob(E.b64),n=b.length,u=new Uint8Array(n);for(var i=0;i<n;i++)u[i]=b.charCodeAt(i);E._u16=new Uint16Array(u.buffer);}catch(e){return null;}}var r=Math.floor((lat-E.lat0)/E.dlat),c=Math.floor((lon-E.lon0)/E.dlon);if(r<0||c<0||r>=E.rows||c>=E.cols)return null;return E._u16[r*E.cols+c];};
